import React from "react";

// Import overlays
import rain from "./overlays/rain.gif";
import snow from "./overlays/snow.gif";
import cloudy from "./overlays/cloudy.gif";
import thunderstorm from "./overlays/thunderstorm.gif";
import night from "./overlays/night.gif";
import noon from "./overlays/noon.gif";
import rainNight from "./overlays/rainNight.gif";
import PCdawn from "./overlays/PCdawn.gif";

export default function WeatherOverlay({ weatherCondition, isDaytime }) {
  const getOverlay = () => {
    const condition = weatherCondition?.toLowerCase();

    if (condition?.includes("rain")) return isDaytime ? rain : rainNight;
    if (condition?.includes("snow")) return snow;
    if (condition?.includes("thunder")) return thunderstorm;

    if (condition?.includes("cloud")) return isDaytime ? cloudy : PCdawn;

    if (condition?.includes("clear") || condition?.includes("sun")) {
      return isDaytime ? noon : night;
    }

    // Fallback
    return isDaytime ? noon : night;
  };

  return (
    <div className="absolute top-0 left-0 w-full h-full z-0 pointer-events-none overflow-hidden">
      <img
        src={getOverlay()}
        alt="weather overlay"
        className="w-full h-full object-cover"
        style={{ opacity: 1 }}
      />
    </div>
  );
}
